<script>
(function() {
  var conversion = {{DLV - conversion}};
  var step = {{DLV - dsp_step}};
  var value = {{DLV - conversion_value}} || 0;
  var quality = {{DLV - aps_current}} || 0;

  if (!conversion) {
    console.warn('? AdKernel DSP Postback NOT fired - Missing conversion');
    return;
  }

  var img = new Image();
  img.src = 'https://rtb2-useast.amplifai.it.com/conversion?cid=' + conversion + 
            '&step=' + (step || 'step_3') + 
            '&value=' + value + 
            '&quality_score=' + quality;

  console.log('? AdKernel DSP Postback Fired:', {
    conversion: conversion,
    step: step,
    value: value,
    quality_score: quality,
    url: img.src
  });
})();
</script>
